        public string LoginSelect(Login Login)//Validando Login na Tela Inicial
        {
            Conexao.Open();
            FbDataReader dr;
            DataTable DtLogin = new DataTable();
            FbDataAdapter Adapter = new FbDataAdapter("SELECT id_usuario, nome_usuario FROM usuario WHERE nome_usuario='" + Login.Nome + "' AND senha='" + Login.Senha + "';", Conexao);
            Adapter.Fill(DtLogin);
            if (DtLogin.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                string retorno;
                dr = Adapter.SelectCommand.ExecuteReader();
                dr.Read();
                retorno = dr.GetString(0) + "—" + dr.GetString(1);
                dr.Close();
                Conexao.Close();
                return retorno;
            }
        }

        public bool LoginSelectFuncao(Login Login, string sqlfuncao)
        {
            Conexao.Open();
            DataTable DtLogin = new DataTable();
            FbDataAdapter Adapter = new FbDataAdapter("SELECT id_usuario, nome_usuario FROM usuario WHERE nome_usuario='" + Login.Nome + "' AND senha='" + Login.Senha + "'" + sqlfuncao + " AND permissao_usuarios=1;", Conexao);
            Adapter.Fill(DtLogin);
            if (DtLogin.Rows.Count == 0)
            {
                Conexao.Close();
                return false;
            }
            else
            {
                Conexao.Close();
                return true;
            }
        }

        //VALIDADE
        public void Salvar_Validade(Validade Val)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO validade (n_lote, data_validade, id_produto, id_dfe, data_cadastro, data_fabricacao, horario_fabricacao)VALUES(" + Val.N_Lote + ", " + Val.Data_Validade + ", " + Val.Cod_Produto + ", " + Val.Cod_Dfe + ", " + Val.Data_Cadastro + ", " + Val.Data_Fabricacao + ", " + Val.Horario_Fabricacao + ");", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }


        public void Alterar_Validade(Validade Val)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("UPDATE validade SET n_lote=" + Val.N_Lote + ", data_validade=" + Val.Data_Validade + ", id_produto=" + Val.Cod_Produto + ", id_dfe=" + Val.Cod_Dfe + ", data_fabricacao=" + Val.Data_Fabricacao + ", horario_fabricacao=" + Val.Horario_Fabricacao + " WHERE id_validade=" + Val.Codigo + ";", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

        public void Excluir_Validade(Validade Val)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("DELETE FROM validade WHERE id_validade=" + Val.Codigo + ";", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

        

