        //XML
        public void Salvar_XML(XML Xml)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO xml (id_dfe, texto_xml, saida)VALUES(" + Xml.Cod_DFe+ ", @xml, " + Xml.Saida + ");", Conexao);
            Comandos.Parameters.Add("@xml", FbDbType.VarChar).Value = Xml.Texto_XML;
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

        public void Excluir_XML(XML Xml)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("DELETE FROM xml WHERE id_dfe=" + Xml.Cod_DFe + " AND saida=0;", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

