        //DFE
        public void Salvar_DFe(DFE NFe)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO dfe (chave_dfe, emissao, modelo, numero_nf, serie, data_emissao, hora_emissao, data_saida, hora_saida, id_emitente_destinatario, nome_emitente_destinatario, total_produtos, descontos, frete, despesas, valor_total_nf, observacao, data_cadastro, descricao_cfop_natop, importado, tipo_emitente_destinatario, seguro, ipi, icms, icms_st, situacao, codigo_aleatorio, finalidade, consumidor_final, tipo_operacao, n_seq_cce, cpf_cnpj_emit_dest, id_venda, id_devolucao, origem_venda, base_calculo_icms, base_calculo_icms_st, total_aprox_trib)VALUES(" + NFe.Chave_DFe + ", " + NFe.Emissao + ", " + NFe.Modelo + ", " + NFe.Numero_NF + ", " + NFe.Serie + ", " + NFe.Data_Emissao + ", " + NFe.Hora_Emissao + ", " + NFe.Data_Saida + ", " + NFe.Hora_Saida + ", " + NFe.Cod_Emitente_Destinatario + ", " + NFe.Nome_Emitente_Destinatario + ", " + NFe.Total_Produtos + ", " + NFe.Descontos + ", " + NFe.Frete + ", " + NFe.Despesas + ", " + NFe.Valor_Total_NF + ", " + NFe.Observacao + ", " + NFe.Data_Cadastro + ", " + NFe.Descricao_CFOP + ", " + NFe.Importado + ", " + NFe.Tipo_Emitente_Destinatario + ", " + NFe.Seguro + ", " + NFe.IPI + ", 0, 0, " + NFe.Situacao + ", " + NFe.Codigo_Aleatorio + ", " + NFe.Finalidade + ", " + NFe.Consumidor_Final + ", " + NFe.Tipo_Operacao + ", " + NFe.N_Seq_CCe + ", " + NFe.CPF_CNPJ_Emitente_Destinatario + ", " + NFe.Cod_Venda + ", " + NFe.Cod_Devolucao + ", " + NFe.Origem_Venda + ", " + NFe.Base_Calculo_ICMS + ", " + NFe.Base_Calculo_ICMS_ST + ", " + NFe.Total_Aprox_Trib + ");", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

