        public DataTable Sel_Saidas_Produtos_Dados(string sqldata, string sqlproduto, string sqlconsumidor, string sqlfornecedor, string sqltipo, string sqlusuario, string sqlum, string sqlcodpdvcomputador, string sqlcodvenda, string sqlservico, string sqlcompservico, string sqltabelaservico, string sqlcompproduto, string sqltabelaproduto, string sqltipoitem)
        {
            Conexao.Open();
            DataTable DtPDV = new DataTable();
            FbDataAdapter Adapter;
            Adapter = new FbDataAdapter("SELECT DISTINCT venda.id_venda, venda.data as data, venda.hora as hora, item_venda.id_produto, item_venda.descricao, item_venda.quantidade, item_venda.um, item_venda.valor_unitario, item_venda.valor_desconto + item_venda.valor_desconto_item as valor_desconto, item_venda.valor_acrescimo + item_venda.valor_acrescimo_item as valor_acrescimo, item_venda.valor_total_a_desc_acresc as valor_total, (SELECT FIRST 1 id_fornecedor FROM entrada_produto WHERE " + sqlfornecedor + "ORDER BY id_entrada_produto DESC), (SELECT FIRST 1 nome_fornecedor FROM entrada_produto WHERE " + sqlfornecedor + "ORDER BY id_entrada_produto DESC), venda.id_consumidor as id_cons, venda.nome_consumidor as nome_cons, venda.id_usuario, venda.nome_usuario, venda.tipo, (SELECT COUNT(id_fornecedor) FROM entrada_produto WHERE " + sqlfornecedor + ") AS qtde_forn_prod_item_venda, venda.id_pdv_computador, null as finalidade, item_venda.tipo FROM item_venda, venda " + sqltabelaservico + sqltabelaproduto + sqldata + sqlconsumidor + sqltipo + sqlusuario + sqlum + sqlcodpdvcomputador + sqlcodvenda + sqlservico + sqlproduto + sqltipoitem + " AND item_venda.id_venda=venda.id_venda " + sqlcompservico + sqlcompproduto + " AND venda.parcial<>1 ORDER BY venda.id_venda ASC, item_venda.id_item ASC;", Conexao);
            Adapter.Fill(DtPDV);
            if (DtPDV.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                Conexao.Close();
                return DtPDV;
            }
        }

        public DataTable Sel_Saidas_Produtos_Dados_Dfe(string sqldatadfe, string sqlprodutodfe, string sqlconsumidordfe, string sqlfornecedordfe, string sqlumdfe, string sqlfinalidade, string sqlcsosndfe, string sqlcfopdfe, string sqltipodfe, string sqltipoitemdfe)
        {
            Conexao.Open();
            DataTable DtPDV = new DataTable();
            FbDataAdapter Adapter = new FbDataAdapter("SELECT id_venda, dfe.data_cadastro as data, CAST(dfe.data_cadastro AS TIME) as hora, item_dfe.id_produto, item_dfe.descricao, item_dfe.quantidade, item_dfe.um, item_dfe.valor_unitario, item_dfe.valor_desconto, item_dfe.valor_acrescimo, item_dfe.valor_total, (SELECT FIRST 1 id_fornecedor FROM entrada_produto WHERE " + sqlfornecedordfe + "ORDER BY id_entrada_produto DESC), (SELECT FIRST 1 nome_fornecedor FROM entrada_produto WHERE " + sqlfornecedordfe + "ORDER BY id_entrada_produto DESC), dfe.id_emitente_destinatario, dfe.nome_emitente_destinatario, null as id_usuario, null as nome_usuario, modelo as tipo, (SELECT COUNT(id_fornecedor) FROM entrada_produto WHERE " + sqlfornecedordfe + ") AS qtde_forn_prod_item_venda, null as id_pdv_computador, dfe.finalidade, 'PRODUTO' as tipo FROM item_dfe, dfe, produto " + sqldatadfe + sqlprodutodfe + sqlconsumidordfe + sqlumdfe + sqlcsosndfe + sqlcfopdfe + sqlfinalidade + sqltipodfe + sqltipoitemdfe + " AND item_dfe.id_dfe=dfe.id_dfe AND item_dfe.id_produto=produto.id_produto AND dfe.situacao<>'INUTILIZADA' AND dfe.situacao<>'CANCELADA' ORDER BY dfe.data_cadastro ASC, item_dfe.id_item ASC;", Conexao);
            Adapter.Fill(DtPDV);
            if (DtPDV.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                Conexao.Close();
                return DtPDV;
            }
        }

