        public void Alterar_Imagem_Logo(MinhaEmpresa Emp, bool nulo)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("UPDATE minha_empresa SET imagem_logo=@imagem_logo WHERE id_minha_empresa=" + Emp.Codigo + ";", Conexao);
            if (nulo == false)
            {
                Comandos.Parameters.Add("@imagem_logo", FbDbType.Binary).Value = Emp.Imagem_Logo;
            }
            else
            {
                Comandos.Parameters.Add("@imagem_logo", FbDbType.Binary).Value = DBNull.Value;
            }
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

