        public short Val_Grupo_Descricao_Alt(Grupo Grup)
        {
            Conexao.Open();
            DataTable DtGrup = new DataTable();
            FbDataReader dr;
            FbDataAdapter Adapter = new FbDataAdapter("SELECT id_grupo FROM grupo WHERE descricao='" + Grup.Descricao + "' AND tabela_destino='" + Grup.Tabela_Destino + "';", Conexao);
            Adapter.Fill(DtGrup);
            if (DtGrup.Rows.Count == 0)
            {
                Conexao.Close();
                return 0;
