        public void Salvar_Produto(Produto Prod)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO produto (palavra_chave, descricao, um, id_marca, desc_marca, id_grupo, desc_grupo, id_subgrupo, desc_subgrupo, cod_barra, preco, observacao, referencia, estoque_min, estoque_max, est_saldo_atual, data_cadastro, id_localizacao, desc_localizacao, acrescimo_porc, desconto_porc, alertar_estoque, dest_est_baixo, csosn, aliq_icms, cst, ncm, cest, importado_dfe, excecao_ncm, imagem_prod, cst_ibs_cbs, cclass_trib, aliq_ibs_mun, aliq_ibs_est, aliq_cbs, situacao)VALUES(" + Prod.Palavra_Chave + ", " + Prod.Descricao + ", " + Prod.UM + ", " + Prod.Cod_Marca + ", " + Prod.Desc_Marca + ", " + Prod.Cod_Grupo + ", " + Prod.Desc_Grupo + ", " + Prod.Cod_SubGrupo + ", " + Prod.Desc_SubGrupo + ", " + Prod.Cod_Barra + ", " + Prod.Preco + ", " + Prod.Observacao + ", " + Prod.Referencia + ", " + Prod.Estoque_Min + ", " + Prod.Estoque_Max + ", " + Prod.Saldo_Atual + ", " + Prod.Data_Cadastro + ", " + Prod.Cod_Localizacao + ", " + Prod.Desc_Localizacao + ", " + Prod.Acrescimo_Porc + ", " + Prod.Desconto_Porc + ", " + Prod.Alertar_Estoque + ", " + Prod.Dest_Est_Baixo + ", " + Prod.CSOSN + ", " + Prod.Aliquota + ", " + Prod.CST + ", " + Prod.NCM + ", " + Prod.CEST + ", " + Prod.Importado_DFe + ", " + Prod.Excecao_NCM + ", @imagem_prod, " + Prod.CST_IBS_CBS + ", " + Prod.CClass_Trib + ", " + Prod.Aliq_IBS_Mun + ", " + Prod.Aliq_IBS_Est + ", " + Prod.Aliq_CBS + ", " + Prod.Situacao + ");", Conexao);
            Comandos.Parameters.Add("@imagem_prod", FbDbType.Binary).Value = Prod.Imagem_Prod;
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

