        public void Alterar_Imagem_Produto(Produto Prod, bool nulo)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("UPDATE produto SET imagem_prod=@imagem_prod WHERE id_produto=" + Prod.Codigo + ";", Conexao);
            if (nulo == false)
            {
                Comandos.Parameters.Add("@imagem_prod", FbDbType.Binary).Value = Prod.Imagem_Prod;
            }
            else
            {
                Comandos.Parameters.Add("@imagem_prod", FbDbType.Binary).Value = DBNull.Value;
            }
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

