        public DataTable Sel_Prod_Frequencia_Entrada(Produto Prod)
        {
            Conexao.Open();
            DataTable DtProd = new DataTable();
            FbDataAdapter Adaper = new FbDataAdapter("SELECT AVG(t.frequencia) AS media_mensal FROM (SELECT i.id_produto, EXTRACT(YEAR FROM d.data_emissao) AS ano, EXTRACT(MONTH FROM d.data_emissao) AS mes, COUNT(DISTINCT d.id_dfe) AS frequencia FROM item_dfe i JOIN dfe d ON d.id_dfe = i.id_dfe WHERE d.emissao = 'TERCEIROS' AND i.id_produto=" + Prod.Codigo + " GROUP BY i.id_produto, EXTRACT(YEAR FROM d.data_emissao), EXTRACT(MONTH FROM d.data_emissao) ) t GROUP BY t.id_produto; ", Conexao);
            Adaper.Fill(DtProd);
            if (DtProd.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                Conexao.Close();
                return DtProd;
            }
        }

