        public void Alterar_Imagem_Os(OS Os, bool nulo)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("UPDATE os SET imagem_os=@imagem_os WHERE id_os=" + Os.Codigo + ";", Conexao);
            if (nulo == false)
            {
                Comandos.Parameters.Add("@imagem_os", FbDbType.Binary).Value = Os.Imagem_OS;
            }
            else
            {
                Comandos.Parameters.Add("@imagem_os", FbDbType.Binary).Value = DBNull.Value;
            }
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

