        public DataTable Sel_Serv_Frequencia_Venda(Servico Serv)
        {
            Conexao.Open();
            DataTable DtServ = new DataTable();
            FbDataAdapter Adaper = new FbDataAdapter("SELECT AVG(DATEDIFF(DAY FROM VendaAnterior TO DataVenda)) AS FrequenciaMediaDias FROM(SELECT v.data AS DataVenda, (SELECT MAX(v2.data) FROM VENDA v2 JOIN ITEM_VENDA iv2 ON iv2.id_venda = v2.id_venda WHERE iv2.id_produto = iv.id_produto AND v2.data < v.data AND iv2.tipo='SERVICO' AND v2.parcial<>1) AS VendaAnterior FROM VENDA v JOIN ITEM_VENDA iv ON iv.id_venda = v.id_venda WHERE iv.id_produto=" + Serv.Codigo + " AND iv.tipo='SERVICO' AND v.parcial<>1 GROUP BY v.data, iv.id_produto) T WHERE VendaAnterior IS NOT NULL; ", Conexao);
            Adaper.Fill(DtServ);
            if (DtServ.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                Conexao.Close();
                return DtServ;
            }
        }

