        public void Salvar_Cliente(ClieCons Clie)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO Cliente (nome, endereco, numero, bairro, cidade, uf, cep, pessoa, data_cadastro, palavra_chave, fantasia, cpf_cnpj, ie_rg, telefone, fax, celular, complemento, genero, email, nome_pai, cpf_pai, celular_pai, email_pai, nome_mae, cpf_mae, celular_mae, email_mae, observacao, data_nascimento, situacao, numero_avalista, credito, saldo, saldo_credito_loja, avalista, cpf_avalista, rg_avalista, email_avalista, endereco_avalista, bairro_avalista, uf_avalista, cidade_avalista, complemento_avalista, cep_avalista, telefone_avalista, celular_avalista, id_grupo, desc_grupo, id_subgrupo, desc_subgrupo, codigo_municipio, imagem_cliente)VALUES(" + Clie.Nome + ", " + Clie.Endereco + ", " + Clie.Numero + ", " + Clie.Bairro + ", " + Clie.Cidade + ", " + Clie.Uf + ", " + Clie.Cep + ", " + Clie.Pessoa + ", '" + Clie.Data_Cadastro + "', " + Clie.Palavra_Chave + ", " + Clie.Fantasia + ", " + Clie.CPF_CNPJ + ", " + Clie.IE_RG + ", " + Clie.Telefone + ", " + Clie.FAX + ", " + Clie.Celular + ", " + Clie.Complemento + ", " + Clie.Genero + ", " + Clie.Email + ", " + Clie.Nome_Pai + ", " + Clie.CPF_Pai + ", " + Clie.Celular_Pai + ", " + Clie.Email_Pai + ", " + Clie.Nome_Mae + ", " + Clie.CPF_Mae + ", " + Clie.Celular_Mae + ", " + Clie.Email_Mae + ", " + Clie.Observacao + ", " + Clie.Data_Nascimento + ", " + Clie.Situacao + ", " + Clie.Numero_Avalista + ", " + Clie.Credito + ", " + Clie.Saldo + ", " + Clie.Saldo_Credito_Loja + ", " + Clie.Avalista + ", " + Clie.CPF_Avalista + ", " + Clie.RG_Avalista + ", " + Clie.Email_Avalista + ", " + Clie.Endereco_Avalista + ", " + Clie.Bairro_Avalista + ", " + Clie.UF_Avalista + ", " + Clie.Cidade_Avalista + ", " + Clie.Complemento_Avalista + ", " + Clie.CEP_Avalista + ", " + Clie.Telefone_Avalista + ", " + Clie.Celular_Avalista + ", " + Clie.Cod_Grupo + ", " + Clie.Desc_Grupo + ", " + Clie.Cod_SubGrupo + ", " + Clie.Desc_SubGrupo + ", " + Clie.Codigo_Municipio + ", @imagem_cliente)", Conexao);
            Comandos.Parameters.Add("@imagem_cliente", FbDbType.Binary).Value = Clie.Imagem_Cliente;
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

        public void Alterar_Imagem_Cliente(ClieCons Clie, bool nulo)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("UPDATE cliente SET imagem_cliente=@imagem_cliente WHERE id_cliente=" + Clie.Codigo + ";", Conexao);
            if (nulo == false)
            {
                Comandos.Parameters.Add("@imagem_cliente", FbDbType.Binary).Value = Clie.Imagem_Cliente;
            }
            else
            {
                Comandos.Parameters.Add("@imagem_cliente", FbDbType.Binary).Value = DBNull.Value;
            }
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

