        public DataTable Sel_Clie_Intervalo_Compra(ClieCons Clie)
        {
            Conexao.Open();
            DataTable DtClie = new DataTable();
            FbDataAdapter Adaper = new FbDataAdapter("SELECT AVG(DATEDIFF(DAY FROM VendaAnterior TO DataVenda)) AS IntervaloMedioDias FROM(SELECT V.data AS DataVenda, (SELECT MAX(V2.data) FROM venda V2 WHERE V2.id_consumidor = V.id_consumidor AND V2.data < V.data) AS VendaAnterior FROM Venda V WHERE V.id_consumidor=" + Clie.Codigo + ") T WHERE VendaAnterior IS NOT NULL; ", Conexao);
            Adaper.Fill(DtClie);
            if (DtClie.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                Conexao.Close();
                return DtClie;
            }
        }

