        //FORNECEDOR
        public void Salvar_Forn(Fornecedor Forn)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO fornecedor(nome, cpf_cnpj, ie_rg, telefone, cep, endereco, cidade, uf, bairro, email, celular, numero, fax, pessoa, complemento, data_nascimento, fantasia, observacao, genero, palavra_chave, data_cadastro, codigo_municipio, imagem_forn)VALUES(" + Forn.Nome + ", " + Forn.CPF_CNPJ + ", " + Forn.IE_RG + ", " + Forn.Telefone + ", " + Forn.CEP + ", " + Forn.Endereco + ", " + Forn.Cidade + ", " + Forn.UF + ", " + Forn.Bairro + ", " + Forn.Email + ", " + Forn.Celular + ", " + Forn.Numero + ", " + Forn.FAX + ", " + Forn.Pessoa + ", " + Forn.Complemento + ", " + Forn.Data_Nascimento + ", " + Forn.Fantasia + ", " + Forn.Observacao + ", " + Forn.Genero + ", " + Forn.Palavra_Chave + ", " + Forn.Data_Cadastro + ", " + Forn.Codigo_Municipio + ", @imagem_forn);", Conexao);
            Comandos.Parameters.Add("@imagem_forn", FbDbType.Binary).Value = Forn.Imagem_Forn;
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

        public void Alterar_Imagem_Forn(Fornecedor Forn, bool nulo)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("UPDATE fornecedor SET imagem_forn=@imagem_forn WHERE id_fornecedor=" + Forn.Codigo + ";", Conexao);
            if (nulo == false)
            {
                Comandos.Parameters.Add("@imagem_forn", FbDbType.Binary).Value = Forn.Imagem_Forn;
            }
            else
            {
                Comandos.Parameters.Add("@imagem_forn", FbDbType.Binary).Value = DBNull.Value;
            }
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

