        public int Sel_Forn_Ultimo_Cod_Adicionado()
        {
            Conexao.Open();
            DataTable DtForn = new DataTable();
            FbDataReader dr;
            FbDataAdapter Adapter = new FbDataAdapter("SELECT FIRST 1 id_fornecedor FROM fornecedor ORDER BY id_fornecedor DESC;", Conexao);
            Adapter.Fill(DtForn);
            if (DtForn.Rows.Count == 0)
            {
                Conexao.Close();
                return 0;
            }
            else
            {
                int valor;
                dr = Adapter.SelectCommand.ExecuteReader();
                dr.Read();
                valor = dr.GetInt32(0);
                dr.Close();
                Conexao.Close();
                return valor;
            }
        }

