        public void Salvar_Orcamento(Orcamento Orc)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO orcamento(id_consumidor, nome_consumidor, id_usuario, nome_usuario, data, data_validade, observacao, valor, hora, situacao, id_pdv_computador, valor_real, valor_acrescimo_item, valor_desconto_item, hora_validade, cpf_cnpj_consumidor, id_venda, valor_acrescimo, valor_desconto, desconto_porc, acrescimo_porc)VALUES(" + Orc.Cod_Consumidor + ", " + Orc.Nome_Consumidor + ", " + Orc.Cod_Usuario + ", " + Orc.Nome_Usuario + ", " + Orc.Data + ", " + Orc.Data_Validade + ", " + Orc.Observacao + ", " + Orc.Valor_Total + ", " + Orc.Hora + ", " + Orc.Situacao + ", " + Orc.Cod_PDV_Computador + ", " + Orc.Valor_Total_Real + ", " + Orc.Valor_Acrescimo_Item + ", " + Orc.Valor_Desconto_Item + ", " + Orc.Hora_Validade + ", " + Orc.CPF_CNPJ_Consumidor + ", 0, " + Orc.Valor_Acrescimo + ", " + Orc.Valor_Desconto + ", " + Orc.Desconto_Porc + ", " + Orc.Acrescimo_Porc + ");", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

