        //FUNCIONARIO
        public void Salvar_Funcionario(Funcionario Func)
        {
            Conexao.Open();                                                                                                                                                                                                                                         //, , , , identificadorcod_barra, nome,                                                                                                   
            FbCommand Comandos = new FbCommand("INSERT INTO funcionario(palavra_chave, nome, data_nascimento, cpf, rg, sexo, endereco, numero, complemento, bairro, uf, cidade, cep, telefone, fax, celular, email, observacao, data_cadastro, imagem_func)VALUES(" + Func.Palavra_Chave + ", " + Func.Nome + ", " + Func.Data_Nascimento + ", " + Func.CPF + ", " + Func.RG + ", " + Func.Sexo + ", " + Func.Endereco + ", " + Func.Numero + ", " + Func.Complemento + ", " + Func.Bairro + ", " + Func.UF + ", " + Func.Cidade + ", " + Func.CEP + ", " + Func.Telefone + ", " + Func.FAX + ", " + Func.Celular + ", " + Func.Email + ", " + Func.Observacao + ", " + Func.Data_Cadastro + ", @imagem_func);", Conexao);
            Comandos.Parameters.Add("@imagem_func", FbDbType.Binary).Value = Func.Imagem_Func;
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

        public void Alterar_Imagem_Funcionario(Funcionario Func, bool nulo)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("UPDATE funcionario SET imagem_func=@imagem_func WHERE id_funcionario=" + Func.Codigo + ";", Conexao);
            if (nulo == false)
            {
                Comandos.Parameters.Add("@imagem_func", FbDbType.Binary).Value = Func.Imagem_Func;
            }
            else
            {
                Comandos.Parameters.Add("@imagem_func", FbDbType.Binary).Value = DBNull.Value;
            }
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

