            FbCommand Comandos = new FbCommand("INSERT INTO localizacao(palavra_chave, descricao, data_cadastro)VALUES(" + Loc.Palavra_Chave + ", " + Loc.Descricao + ", " + Loc.Data_Cadastro + ");", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
