        public void Executar_Arquivo_SQL(string sql)
        {
            if (Conexao.State == ConnectionState.Open)
            {
                Conexao.Close();
            }
            //
            Conexao.Open();
            FbCommand Comandos = new FbCommand(sql, Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }

