        public string Sel_Chave_Pix_Alt(PSP Psp)
        {
            Conexao.Open();
            DataTable DtPag = new DataTable();
            FbDataReader dr;
            FbDataAdapter Adapter = new FbDataAdapter("SELECT id_psp FROM psp WHERE chave_pix='" + Psp.Chave_PIX + "';", Conexao);
            Adapter.Fill(DtPag);
            if (DtPag.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                string valor;
                dr = Adapter.SelectCommand.ExecuteReader();
                dr.Read();
                valor = dr.GetString(0);
                dr.Close();
                Conexao.Close();
                return valor;
            }
        }


