        public string Sel_Ultima_Venda()
        {
            Conexao.Open();
            DataTable DtVenda = new DataTable();
            FbDataReader dr;
            FbDataAdapter Adapter = new FbDataAdapter("SELECT FIRST 1 id_venda FROM venda ORDER BY id_venda DESC;", Conexao);
            Adapter.Fill(DtVenda);
            if (DtVenda.Rows.Count == 0)
            {
                Conexao.Close();
                return null;
            }
            else
            {
                string valor;
                dr = Adapter.SelectCommand.ExecuteReader();
                dr.Read();
                valor = dr.GetString(0);
                dr.Close();
                Conexao.Close();
                return valor;
            }
        }

