            Conexao.Open();
            DataTable DtConta = new DataTable();
            FbDataAdapter Adapter = new FbDataAdapter("SELECT id_conta_receber, descricao, n_promissoria, ocorrencia_parc, cod_barra, data_emissao, data_vencimento, tipo_documento, tipo_consumidor, id_consumidor, nome_consumidor, id_grupo, desc_grupo, id_subgrupo, desc_subgrupo, valor_documento, valor_real, data_desconto, desconto_porc, valor_desconto, multa_porc, valor_multa, juros_am_porc, valor_juros_am, situacao, valor_total_pago, troco, data_baixa, hora_baixa, observacao, palavra_chave, data_cadastro, tipo_entrada, id_venda, ignorar_multa, ignorar_juros_am, id_usuario_baixa, nome_usuario_baixa FROM conta_receber WHERE id_consumidor='" + codigo + "' AND tipo_consumidor='" + tipo_consumidor + "' AND tipo_entrada='MANUAL' ORDER BY id_conta_receber ASC;", Conexao);
            Adapter.Fill(DtConta);
