        //CONTA_RECEBER
        public void Salvar_Conta_Receber(ContasReceber Conta)
        {
            Conexao.Open();
            FbCommand Comandos = new FbCommand("INSERT INTO conta_receber(ocorrencia_parc, descricao, data_emissao, data_vencimento, tipo_documento, id_grupo, desc_grupo, id_subgrupo, desc_subgrupo, valor_documento, data_desconto, desconto_porc, valor_desconto, multa_porc, valor_multa, juros_am_porc, valor_juros_am, id_consumidor, nome_consumidor, observacao, data_cadastro, valor_real, data_baixa, situacao, valor_total_pago, tipo_consumidor, palavra_chave, id_venda, troco, hora_baixa, ignorar_multa, ignorar_juros_am, id_usuario_baixa, nome_usuario_baixa, n_promissoria, baixa_apos_vencimento, id_pdv_computador_baixa, id_controle_cheque)VALUES(" + Conta.Ocorrencia_Parc + ", " + Conta.Descricao + ", " + Conta.Data_Emissao + ", " + Conta.Data_Vencimento + ", " + Conta.Tipo_Documento + ", " + Conta.Cod_Grupo + ", " + Conta.Desc_Grupo + ", " + Conta.Cod_Subgrupo + ", " + Conta.Desc_Subgrupo + ", " + Conta.Valor_Documento + ", " + Conta.Data_Desconto + ", " + Conta.Desconto_Porc + ", " + Conta.Valor_Desconto + ", " + Conta.Multa_Porc + ", " + Conta.Valor_Multa + ", " + Conta.Juros_Am_Porc + ", " + Conta.Valor_Juros_Am + ", " + Conta.Cod_Consumidor + ", " + Conta.Nome_Consumidor + ", " + Conta.Observacao + ", " + Conta.Data_Cadastro + ", " + Conta.Valor_Real + ", " + Conta.Data_Baixa + ", " + Conta.Situacao + ", " + Conta.Valor_Total_Pago + ", " + Conta.Tipo_Consumidor + ", " + Conta.Palavra_Chave + ", " + Conta.Cod_Venda + ", 0, " + Conta.Hora_Baixa + ", 0, 0, " + Conta.Cod_Usuario_Baixa + ", " + Conta.Nome_Usuario_Baixa + ", " + Conta.N_Promissoria + ", 0, " + Conta.Cod_PDV_Computador_Baixa + ", " + Conta.Cod_Controle_Cheque + ");", Conexao);
            Comandos.ExecuteNonQuery();
            Conexao.Close();
        }


        public void Alterar_Situacao_Conta_Receber_Venda(ContasReceber Conta)
